// // This module implements a 4-bit binary counter with synchronous reset and disable functionality.
module counter_4bit (  
    input wire clk,  
    input wire reset,  
    input wire enable,  
    output reg [3:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset)  
            count <= 4'b0000;  
        else if (enable)  
            count <= count + 1;  
    end  
endmodule
